  1→import {
  2→	AlertTriangle,
  3→	Building2,
  4→	Check,
  5→	Copy,
  6→	Loader2,
  7→	Mail,
  8→	Plus,
  9→	Trash2,
 10→	UserPlus,
 11→	X,
 12→} from "lucide-react";
 13→import { useEffect, useState } from "react";
 14→import { Link, useNavigate } from "react-router-dom";
 15→import { AnalyticsCard } from "../../components/analytics/AnalyticsCard";
 16→import { PageHeader } from "../../components/analytics/PageHeader";
 17→import { DeleteOrganizationDialog } from "../../components/DeleteOrganizationDialog";
 18→import { Badge } from "../../components/ui/badge";
 19→import { Button } from "../../components/ui/button";
 20→import { Input } from "../../components/ui/input";
 21→import {
 22→	Select,
 23→	SelectContent,
 24→	SelectItem,
 25→	SelectTrigger,
 26→	SelectValue,
 27→} from "../../components/ui/select";
 28→import { useOrganization } from "../../contexts/OrganizationContext";
 29→import { authClient } from "../../lib/auth-client";
 30→
 31→interface FullOrg {
 32→	id: string;
 33→	name: string;
 34→	slug: string;
 35→	members: readonly {
 36→		id: string;
 37→		userId: string;
 38→		role: string;
 39→		user: { id: string; name: string; email: string; image: string | null };
 40→	}[];
 41→	invitations: readonly {
 42→		id: string;
 43→		email: string;
 44→		role: string | null;
 45→		status: string;
 46→	}[];
 47→}
 48→
 49→export function OrganizationPage() {
 50→	const { activeOrg, organizations, switchOrg } = useOrganization();
 51→	const navigate = useNavigate();
 52→	const [fullOrg, setFullOrg] = useState<FullOrg | null>(null);
 53→	const [loading, setLoading] = useState(true);
 54→	const [inviteEmail, setInviteEmail] = useState("");
 55→	const [inviteRole, setInviteRole] = useState("member");
 56→	const [inviting, setInviting] = useState(false);
 57→	const [inviteLink, setInviteLink] = useState<string | null>(null);
 58→	const [copied, setCopied] = useState(false);
 59→	const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
 60→
 61→	const fetchOrg = async () => {
 62→		if (!activeOrg) return;
 63→		setLoading(true);
 64→		const res = await authClient.organization.getFullOrganization({
 65→			query: { organizationId: activeOrg.id },
 66→		});
 67→		if (res.data) {
 68→			setFullOrg(res.data as unknown as FullOrg);
 69→		}
 70→		setLoading(false);
 71→	};
 72→
 73→	// biome-ignore lint/correctness/useExhaustiveDependencies: refetch when org changes
 74→	useEffect(() => {
 75→		fetchOrg();
 76→	}, [activeOrg?.id]);
 77→
 78→	const handleInvite = async (e: React.FormEvent) => {
 79→		e.preventDefault();
 80→		if (!inviteEmail.trim()) return;
 81→		setInviting(true);
 82→		const res = await authClient.organization.inviteMember({
 83→			email: inviteEmail.trim(),
 84→			role: inviteRole as "member" | "admin",
 85→		});
