 12→function slugify(name: string): string {
 13→	return name
 14→		.toLowerCase()
 15→		.replace(/[^a-z0-9\s-]/g, "")
 16→		.replace(/\s+/g, "-")
 17→		.replace(/-+/g, "-")
 18→		.slice(0, 48);
 19→}
 20→
 21→export function CreateOrgPage() {
 22→	const navigate = useNavigate();
 23→	const { switchOrg } = useOrganization();
 24→	const [name, setName] = useState("");
 25→	const [slug, setSlug] = useState("");
 26→	const [slugManual, setSlugManual] = useState(false);
 27→	const [creating, setCreating] = useState(false);
 28→	const [error, setError] = useState<string | null>(null);
 29→
 30→	const handleNameChange = (value: string) => {
 31→		setName(value);
 32→		if (!slugManual) {
 33→			setSlug(slugify(value));
 34→		}
 35→	};
 36→
 37→	const handleSubmit = async (e: React.FormEvent) => {
 38→		e.preventDefault();
 39→		if (!name.trim() || !slug.trim()) return;
 40→
 41→		setCreating(true);
 42→		setError(null);
 43→
 44→		const res = await authClient.organization.create({
 45→			name: name.trim(),
 46→			slug: slug.trim(),
 47→		});
 48→
 49→		if (res.error) {
 50→			setError(res.error.message ?? "Failed to create organization");
 51→			setCreating(false);
 52→			return;
 53→		}
 54→
 55→		if (res.data) {
 56→			await switchOrg(res.data.id);
