 40→	useEffect(() => {
 41→		if (!open) {
 42→			setSessionCount(null);
 43→			setLoading(true);
 44→			setSessionAction(null);
 45→			setMigrateTarget("");
 46→			setConfirmName("");
 47→			setDeleting(false);
 48→			setError(null);
