106→						{sessionCount !== null && sessionCount > 0 ? (
107→							<>
108→								<p className="text-sm text-foreground">
109→									This organization has{" "}
110→									<strong>
111→										{sessionCount} session{sessionCount !== 1 ? "s" : ""}
