 23→type Page = "login" | "signup";
 24→
 25→function getCliParams(): { cliCallback: string; state: string } | null {
 26→	const params = new URLSearchParams(window.location.search);
 27→	const cliCallback = params.get("cli_callback");
 28→	const state = params.get("state");
 29→	if (!cliCallback || !state) return null;
 30→	try {
 31→		const url = new URL(cliCallback);
 32→		if (url.hostname !== "127.0.0.1") return null;
 33→	} catch {
 34→		return null;
 35→	}
 36→	return { cliCallback, state };
 37→}
 38→
 39→function getValidRedirect(): string | null {
 40→	const params = new URLSearchParams(window.location.search);
 41→	const redirect = params.get("redirect");
 42→	if (!redirect) return null;
 43→	if (!redirect.startsWith("/") || redirect.startsWith("//")) return null;
 44→	return redirect;
 45→}
 46→
 47→function App() {
 48→	const { data: session, isPending } = authClient.useSession();
 49→	const [page, setPage] = useState<Page>("login");
 50→	const [cliRedirecting, setCliRedirecting] = useState(false);
 51→	const cliParams = getCliParams();
 52→	const { resolvedTheme } = useTheme();
 53→	const logoSrc =
 54→		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 55→
 56→	useEffect(() => {
 57→		if (!session || !cliParams || cliRedirecting) return;
 58→		setCliRedirecting(true);
 59→
 60→		fetch("/api/cli-token", { credentials: "include" })
 61→			.then((res) => res.json())
 62→			.then((data: { token: string }) => {
 63→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 64→				window.location.href = redirectUrl;
 65→			});
 66→	}, [session, cliParams, cliRedirecting]);
 67→
 68→	if (isPending) {
 69→		return (
 70→			<div className="flex min-h-screen items-center justify-center">
 71→				<p className="text-muted-foreground">Loading...</p>
 72→			</div>
 73→		);
 74→	}
 75→
 76→	if (cliRedirecting) {
 77→		return (
 78→			<div className="flex min-h-screen items-center justify-center">
 79→				<p className="text-muted-foreground">Completing CLI login...</p>
 80→			</div>
 81→		);
 82→	}
 83→
 84→	if (!session) {
 85→		return (
 86→			<div className="flex min-h-screen flex-col items-center justify-center gap-6">
 87→				<img src={logoSrc} alt="Rudel" className="h-10 w-10" />
 88→				{page === "login" ? (
 89→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 90→				) : (
 91→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 92→				)}
 93→			</div>
 94→		);
 95→	}
 96→
 97→	return (
 98→		<Routes>
 99→			<Route
100→				path="/"
101→				element={<Navigate to={getValidRedirect() || "/dashboard"} replace />}
102→			/>
103→			<Route
104→				path="/invitation/:invitationId"
105→				element={<AcceptInvitationPage />}
106→			/>
107→			<Route path="/dashboard" element={<DashboardLayout />}>
