 1→import { getAllAdapters } from "@rudel/agent-adapters";
 2→import { escapeString, getClickhouse } from "../clickhouse.js";
 3→
 4→export async function getOrgSessionCount(orgId: string): Promise<number> {
 5→	const ch = getClickhouse();
 6→	const escaped = escapeString(orgId);
 7→	const tables = getAllAdapters().map((a) => a.rawTableName);
 8→	const results = await Promise.all(
 9→		tables.map((table) =>
10→			ch.query<{ count: string }>(
11→				`SELECT count() as count FROM ${table} WHERE organization_id = '${escaped}'`,
12→			),
13→		),
14→	);
15→	return results.reduce((sum, rows) => sum + Number(rows[0]?.count ?? 0), 0);
16→}
17→
18→export async function deleteOrgSessions(orgId: string): Promise<void> {
19→	const ch = getClickhouse();
20→	const escaped = escapeString(orgId);
21→	const tables = getAllAdapters().map((a) => a.rawTableName);
22→	await Promise.all([
23→		...tables.map((table) =>
24→			ch.execute(`DELETE FROM ${table} WHERE organization_id = '${escaped}'`),
25→		),
26→		ch.execute(
27→			`DELETE FROM rudel.session_analytics WHERE organization_id = '${escaped}'`,
28→		),
29→	]);
30→}
31→
32→export async function migrateOrgSessions(
33→	fromOrgId: string,
34→	toOrgId: string,
35→): Promise<void> {
36→	const ch = getClickhouse();
37→	const from = escapeString(fromOrgId);
38→	const to = escapeString(toOrgId);
39→	const tables = getAllAdapters().map((a) => a.rawTableName);
40→	await Promise.all([
41→		...tables.map((table) =>
42→			ch.execute(
43→				`ALTER TABLE ${table} UPDATE organization_id = '${to}', ingested_at = now64(3) WHERE organization_id = '${from}'`,
44→			),
45→		),
46→		ch.execute(
47→			`ALTER TABLE rudel.session_analytics UPDATE organization_id = '${to}', ingested_at = now64(3) WHERE organization_id = '${from}'`,
48→		),
49→	]);
50→}
